## Goal
Identify merged PRs and clean them up from local tracking.

## Background
After a PR merges:
1. The PR is in "merged" state on GitHub
2. The branch can be deleted
3. Local tracking should stop including it in the stack

## Implementation

### Detecting Merged PRs
```typescript
async function getMergedPRUnits(
  units: PRUnit[],
  config: BranchNameConfig
): Promise<PRUnit[]> {
  const merged: PRUnit[] = [];

  for (const unit of units) {
    const branch = getBranchName(unit.id, config);
    const pr = await findPRByBranch(branch);

    if (pr?.state === 'merged') {
      merged.push(unit);
    }
  }

  return merged;
}
```

### Cleanup Actions
1. **Delete remote branch** (optional):
   ```bash
   git push origin --delete taspr/msims/a1b2c3d4
   ```

2. **Report merged PRs**:
   ```
   ✓ PR #142 merged to main
   ✓ Deleted branch taspr/msims/a1b2c3d4
   ```

### During Sync
```typescript
async function cleanupMergedPRs(units: PRUnit[]): Promise<PRUnit[]> {
  const merged = await getMergedPRUnits(units);

  if (merged.length > 0) {
    console.log(\`✓ Removed \${merged.length} merged PR(s) from tracking\`);

    // Optionally delete remote branches
    for (const unit of merged) {
      await deleteRemoteBranch(getBranchName(unit.id));
    }
  }

  // Return remaining (non-merged) units
  return units.filter(u => !merged.includes(u));
}
```

