// src/cli/commands/view.ts

async function viewCommand() {
  const result = await parseStack();
  if (!result.ok) { /* handle error */ }

  // Get branch config for lookups
  const config = await getBranchNameConfig();

  // Enrich units with PR info
  const enrichedUnits = await Promise.all(
    result.units.map(async unit => {
      const branch = getBranchName(unit.id, config);
      const pr = await findPRByBranch(branch);
      return { ...unit, pr };
    })
  );

  // Format and display
  console.log(formatStackView(enrichedUnits));
}
```

### Updated Formatting
```typescript
function formatPRUnit(unit: EnrichedPRUnit): string {
  const status = getPRStatusIcon(unit.pr);
  const prNum = unit.pr ? \`#\${unit.pr.number} \` : '';
  const title = unit.title;

  let output = \`  \${status} \${prNum}\${title}\\n\`;

  // Commits
  for (const commit of unit.commits) {
    output += \`    └─ \${commit.slice(0, 8)}\\n\`;
  }

  // PR URL
  if (unit.pr) {
    output += \`    \${unit.pr.url}\\n\`;
  }

  return output;
}

function getPRStatusIcon(pr: PRInfo | null): string {
  if (!pr) return '○';
  switch (pr.state) {
    case 'open': return '◐';
    case 'merged': return '✓';
    case 'closed': return '✗';
    default: return '○';
  }
}
```

