## Goal
Force-push branches that have changed after local commit amendments.

## Implementation

```typescript
// src/github/branches.ts

async function forcePushBranch(commitHash: string, branchName: string): Promise<void> {
  await $\`git push --force origin ${commitHash}:refs/heads/${branchName}\`;
}

async function updateChangedBranches(
  units: PRUnit[],
  statuses: Map<string, SyncStatus>,
  config: BranchNameConfig
): Promise<string[]> {
  const updated: string[] = [];

  for (const unit of units) {
    const status = statuses.get(unit.id)!;

    if (status.needsUpdate) {
      await forcePushBranch(status.localCommit, status.branchName);
      updated.push(status.branchName);
    }
  }

  return updated;
}
```

### Safety Considerations
- Force push is destructive—overwrites remote branch
- Fine for taspr branches (single owner)
- GitHub retains old commits briefly via reflog

### Reporting
```
$ taspr sync

✓ Updated 2 branch(es):
  • taspr/msims/a1b2c3d4 (b2c3d4e5 → new-hash)
  • taspr/msims/f7e8d9c0 (c3d4e5f6 → new-hash)
```

