## Goal
Generate stable branch names for PRUnits following the pattern `<prefix>/<username>/<pr-id>`.

## Implementation

```typescript
// src/github/branches.ts

interface BranchNameConfig {
  prefix: string;      // From git config or default "taspr"
  username: string;    // From GitHub API
}

async function getBranchNameConfig(): Promise<BranchNameConfig> {
  // Get prefix from git config
  const prefixResult = await $`git config --get taspr.branchPrefix`.nothrow();
  const prefix = prefixResult.exitCode === 0 
    ? prefixResult.stdout.toString().trim() 
    : 'taspr';

  // Get username from GitHub
  const username = await $`gh api user --jq .login`.text();

  return { prefix, username: username.trim() };
}

function getBranchName(prId: string, config: BranchNameConfig): string {
  return `${config.prefix}/${config.username}/${prId}`;
}
```

