## Goal
Implement `taspr land` to merge the bottom ready PR.

## Implementation

```typescript
// src/cli/commands/land.ts

export const landCommand = new Command('land')
  .description('Merge the bottom ready PR in the stack')
  .option('--all', 'Merge all consecutive ready PRs')
  .action(async (options) => {
    // Parse stack and get PR info
    const result = await parseStack();
    if (!result.ok) {
      console.error(formatValidationError(result));
      process.exit(1);
    }

    const config = await getBranchNameConfig();
    const enrichedUnits = await enrichWithPRInfo(result.units, config);

    // Find bottom unmerged PR
    const unmerged = enrichedUnits.filter(u => u.pr?.state === 'open');
    if (unmerged.length === 0) {
      console.log('No unmerged PRs in stack');
      return;
    }

    const bottom = unmerged[0];

    // Check if ready
    const status = await getPRMergeStatus(bottom.pr!.number);
    if (!status.mergeable) {
      console.error(\`✗ PR #\${bottom.pr!.number} is not ready:\\n\`);
      if (status.checksStatus === 'failing') {
        console.error('  • CI checks failing');
      }
      if (status.reviewDecision !== 'approved') {
        console.error('  • Needs approval');
      }
      process.exit(1);
    }

    // Merge
    console.log(\`Merging PR #\${bottom.pr!.number} (\${bottom.title})...\`);
    const result = await mergePR(bottom.pr!.number);
    console.log(\`✓ Merged PR #\${bottom.pr!.number} to main\`);
  });
```

