## Goal
Merge a PR using the GitHub API via gh CLI.

## Implementation

```typescript
// src/github/pr.ts

type MergeMethod = 'merge' | 'squash' | 'rebase';

interface MergeResult {
  sha: string;      // Merge commit SHA
  merged: boolean;
}

async function mergePR(
  prNumber: number,
  method?: MergeMethod
): Promise<MergeResult> {
  // Use gh CLI to merge
  const methodFlag = method ? \`--\${method}\` : '';

  const result = await $\`gh pr merge \${prNumber} \${methodFlag} --json sha,state\`.nothrow();

  if (result.exitCode !== 0) {
    const error = result.stderr.toString();
    if (error.includes('not mergeable')) {
      throw new PRNotMergeableError(prNumber);
    }
    throw new GitHubAPIError(\`Failed to merge PR #\${prNumber}: \${error}\`);
  }

  const data = JSON.parse(result.stdout.toString());
  return { sha: data.sha, merged: true };
}
```

### Checking Mergeability
```typescript
interface PRMergeStatus {
  mergeable: boolean;
  mergeableState: string;
  checksStatus: 'pending' | 'passing' | 'failing';
  reviewDecision: 'approved' | 'review_required' | 'changes_requested';
}

async function getPRMergeStatus(prNumber: number): Promise<PRMergeStatus> {
  const result = await $\`gh pr view \${prNumber} --json mergeable,mergeStateStatus,reviewDecision,statusCheckRollup\`;
  const data = JSON.parse(result.stdout.toString());

  return {
    mergeable: data.mergeable === 'MERGEABLE',
    mergeableState: data.mergeStateStatus,
    checksStatus: getChecksStatus(data.statusCheckRollup),
    reviewDecision: data.reviewDecision?.toLowerCase() || 'review_required',
  };
}
```

