## Goal
Detect and report malformed groups: overlapping groups and unclosed groups.

## Background
Groups must follow strict rules:
1. **No overlapping**: A group cannot start inside another group
2. **Must close**: Every Taspr-Group-Start must have a matching Taspr-Group-End

Validation happens during stack parsing and should return clear, actionable errors.

## Error Types

```typescript
type StackParseResult = 
  | { ok: true; units: PRUnit[] }
  | { ok: false; error: 'unclosed-group'; groupId: string; startCommit: string; groupTitle: string }
  | { ok: false; error: 'overlapping-groups'; 
      group1: { id: string; title: string; startCommit: string };
      group2: { id: string; title: string; startCommit: string };
      overlappingCommit: string }
```

## Validation Algorithm

```typescript
function validateAndDetectPRUnits(commits: CommitInfo[]): StackParseResult {
  let activeGroup: { id: string; title: string; start: string } | null = null;

  for (const commit of commits) {
    const startId = commit.trailers['Taspr-Group-Start'];
    const endId = commit.trailers['Taspr-Group-End'];

    // Check for overlapping groups
    if (startId && activeGroup && startId !== activeGroup.id) {
      return {
        ok: false,
        error: 'overlapping-groups',
        group1: activeGroup,
        group2: { 
          id: startId, 
          title: commit.trailers['Taspr-Group-Title'] || commit.subject,
          startCommit: commit.hash 
        },
        overlappingCommit: commit.hash,
      };
    }

    if (startId && !activeGroup) {
      activeGroup = { 
        id: startId, 
        title: commit.trailers['Taspr-Group-Title'] || commit.subject,
        start: commit.hash 
      };
    }

    if (endId && activeGroup && endId === activeGroup.id) {
      activeGroup = null;
    }
  }

  // Check for unclosed group
  if (activeGroup) {
    return {
      ok: false,
      error: 'unclosed-group',
      groupId: activeGroup.id,
      startCommit: activeGroup.start,
      groupTitle: activeGroup.title,
    };
  }

  // If validation passes, run detection
  return { ok: true, units: detectPRUnits(commits) };
}
```

