## Goal
Find existing PRs for branches to avoid creating duplicates.

## Implementation

```typescript
// src/github/pr.ts

interface PRInfo {
  number: number;
  url: string;
  state: 'open' | 'closed' | 'merged';
  title: string;
}

async function findPRByBranch(branchName: string): Promise<PRInfo | null> {
  const result = await $\`gh pr list --head ${branchName} --json number,url,state,title\`.nothrow();

  if (result.exitCode !== 0) {
    return null;
  }

  const prs = JSON.parse(result.stdout.toString());

  // Return first open PR (should only be one)
  const openPR = prs.find((pr: PRInfo) => pr.state === 'open');
  return openPR || null;
}
```

