// src/github/pr.ts

type ChecksStatus = 'pending' | 'passing' | 'failing';

async function getPRChecksStatus(prNumber: number): Promise<ChecksStatus> {
  const result = await $\`gh pr checks \${prNumber} --json state\`;
  const checks = JSON.parse(result.stdout.toString());

  const states = checks.map((c: any) => c.state);

  if (states.some((s: string) => s === 'FAILURE')) return 'failing';
  if (states.some((s: string) => s === 'PENDING')) return 'pending';
  return 'passing';
}
