async function addGroupTrailers(
  commits: CommitInfo[],
  groupId: string,
  title: string
): Promise<void> {
  const first = commits[0];
  const last = commits[commits.length - 1];

  // Add Start and Title to first commit
  await addTrailersToCommit(first.hash, {
    'Taspr-Group-Start': groupId,
    'Taspr-Group-Title': title,
  });

  // Add End to last commit (if different from first)
  if (last.hash !== first.hash) {
    await addTrailersToCommit(last.hash, {
      'Taspr-Group-End': groupId,
    });
  }
}
