## Goal
Support configuration via git config for branch prefix and default branch.

## Configuration Options

### taspr.branchPrefix
Custom prefix for branch names (default: "taspr"):
```bash
git config taspr.branchPrefix jaspr
# Produces: jaspr/msims/a1b2c3d4 instead of taspr/msims/a1b2c3d4
```

### taspr.defaultBranch
Default branch to stack on (default: auto-detect from origin):
```bash
git config taspr.defaultBranch main
```

## Implementation

```typescript
// src/git/config.ts

interface TasprConfig {
  branchPrefix: string;
  defaultBranch: string;
}

async function getTasprConfig(): Promise<TasprConfig> {
  const [prefixResult, defaultResult] = await Promise.all([
    $\`git config --get taspr.branchPrefix\`.nothrow(),
    $\`git config --get taspr.defaultBranch\`.nothrow(),
  ]);

  const prefix = prefixResult.exitCode === 0 
    ? prefixResult.stdout.toString().trim() 
    : 'taspr';

  let defaultBranch: string;
  if (defaultResult.exitCode === 0) {
    defaultBranch = defaultResult.stdout.toString().trim();
  } else {
    // Auto-detect from origin
    defaultBranch = await detectDefaultBranch();
  }

  return { branchPrefix: prefix, defaultBranch };
}

async function detectDefaultBranch(): Promise<string> {
  // Method 1: Check remote HEAD
  const result = await $\`git symbolic-ref refs/remotes/origin/HEAD\`.nothrow();
  if (result.exitCode === 0) {
    const ref = result.stdout.toString().trim();
    return ref.replace('refs/remotes/origin/', '');
  }

  // Method 2: Common defaults
  for (const branch of ['main', 'master']) {
    const exists = await $\`git rev-parse --verify origin/\${branch}\`.nothrow();
    if (exists.exitCode === 0) return branch;
  }

  throw new Error('Could not detect default branch. Set it with: git config taspr.defaultBranch <branch>');
}
```

