## Goal
Implement the rebase logic that reorders commits and adds group trailers after the user confirms their arrangement in the TUI.

## Context
This is part of Epic 7: Group Management. After the user arranges commits and assigns groups in the TUI, this module performs the actual git operations:
1. Reorder commits via interactive rebase
2. Add group trailers (Taspr-Group-Start, Taspr-Group-Title, Taspr-Group-End) to appropriate commits

## Implementation

### Main Function
```typescript
interface GroupAssignment {
  commits: string[];  // Commit hashes in this group
  name: string;       // User-provided group name
}

interface ReorderResult {
  success: boolean;
  error?: string;
  conflictFile?: string;
}

async function reorderAndGroup(
  originalOrder: string[],      // Original commit hashes (oldest first)
  newOrder: string[],           // New commit order
  groups: GroupAssignment[],    // Groups with their commits and names
  options: GitOptions = {}
): Promise<ReorderResult> {
  // 1. Check if reorder is needed
  const needsReorder = !arraysEqual(originalOrder, newOrder);

  // 2. Perform rebase to reorder (if needed)
  if (needsReorder) {
    const rebaseResult = await rebaseToReorder(originalOrder, newOrder, options);
    if (!rebaseResult.success) {
      return rebaseResult;
    }
  }

  // 3. Add group trailers
  for (const group of groups) {
    await addGroupTrailers(group.commits, group.name, options);
  }

  return { success: true };
}
```

### Reordering via Interactive Rebase
```typescript
async function rebaseToReorder(
  originalOrder: string[],
  newOrder: string[],
  options: GitOptions = {}
): Promise<ReorderResult> {
  const { cwd } = options;
  const mergeBase = await getMergeBase(options);

  // Create a sequence editor script that outputs the new order
  const todoScript = createReorderTodoScript(newOrder);
  const scriptPath = join(tmpdir(), \`taspr-reorder-\${Date.now()}.sh\`);

  try {
    await writeFile(scriptPath, todoScript);
    await chmod(scriptPath, '755');

    // Run interactive rebase with custom sequence editor
    const result = cwd
      ? await \$\`GIT_SEQUENCE_EDITOR=\${scriptPath} git -C \${cwd} rebase -i \${mergeBase}\`
          .quiet().nothrow()
      : await \$\`GIT_SEQUENCE_EDITOR=\${scriptPath} git rebase -i \${mergeBase}\`
          .quiet().nothrow();

    if (result.exitCode !== 0) {
      // Check for conflict
      const conflictInfo = await getConflictInfo(options);
      if (conflictInfo) {
        return { 
          success: false, 
          error: 'Rebase conflict',
          conflictFile: conflictInfo.files[0]
        };
      }
      return { success: false, error: result.stderr.toString() };
    }

    return { success: true };
  } finally {
    await unlink(scriptPath).catch(() => {});
  }
}

function createReorderTodoScript(newOrder: string[]): string {
  // Script that rewrites the todo file with commits in new order
  return \`#!/bin/bash
set -e
TODO_FILE="\$1"

# Write new order
cat > "\$TODO_FILE" << 'TODOEOF'
\${newOrder.map(hash => \`pick \${hash}\`).join('\n')}
TODOEOF
\`;
}
```

