## Goal
Detect rebase conflicts and provide clear instructions for resolution.

## Implementation

```typescript
// src/git/rebase.ts

interface ConflictInfo {
  files: string[];
  currentCommit: string;
  currentSubject: string;
}

async function getConflictInfo(): Promise<ConflictInfo | null> {
  // Check if we're in a rebase
  const rebaseDir = await $\`git rev-parse --git-path rebase-merge\`.text();
  const exists = await Bun.file(rebaseDir.trim()).exists();

  if (!exists) return null;

  // Get conflicting files
  const status = await $\`git status --porcelain\`.text();
  const conflicts = status
    .split('\n')
    .filter(line => line.startsWith('UU ') || line.startsWith('AA '))
    .map(line => line.slice(3));

  // Get current commit being rebased
  const head = await $\`git rev-parse HEAD\`.text();
  const subject = await $\`git log -1 --format=%s HEAD\`.text();

  return {
    files: conflicts,
    currentCommit: head.trim().slice(0, 8),
    currentSubject: subject.trim(),
  };
}
```

### Error Message
```typescript
function formatConflictError(info: ConflictInfo): string {
  return \`
✗ Rebase conflict while applying commit \${info.currentCommit}
  "\${info.currentSubject}"

Conflicting files:
\${info.files.map(f => \`  • \${f}\`).join('\n')}

To resolve:
  1. Edit the conflicting files
  2. git add <fixed files>
  3. git rebase --continue
  4. taspr sync

To abort:
  git rebase --abort
\`.trim();
}
```

