  const story = createStory("sync.test.ts");

  afterAll(async () => {
    await story.flush();
  });

  test("skips PR creation for WIP commits", async () => {
    story.begin("skips PR creation for WIP commits");
    story.narrate("If you have a commit prefixed with 'WIP:', taspr will skip creating a PR for it.");

