## Key Principles
- Stories focus on what's being demonstrated, not mechanical setup steps
- Err on the side of showing less; add git output only if it adds clarity for a specific test
- No generic `runGit()` wrapper needed; tests continue using existing git interaction patterns

## Goal
After rebasing, update all affected PR branches.

## Background
After a rebase:
- All commit hashes in the stack have changed
- All remote branches point to old hashes
- All branches need force-pushing

## Implementation

```typescript
// src/core/sync.ts

async function syncAfterRebase(units: PRUnit[]): Promise<void> {
  const config = await getBranchNameConfig();

  console.log('Updating PR branches...');

  let updated = 0;

  for (const unit of units) {
    const branch = getBranchName(unit.id, config);
    const localCommit = unit.commits[unit.commits.length - 1];

    // Force push regardless of whether we think it changed
    // After rebase, everything has changed
    await forcePushBranch(localCommit, branch);
    updated++;

    console.log(\`  ✓ \${branch}\`);
  }

  console.log(\`\\n✓ Updated \${updated} PR branch(es)\`);
}
```

### Full Sync Flow
```typescript
async function sync(options: { open?: boolean }) {
  // 1. Check for dirty state
  await requireCleanWorkingTree();

  // 2. Check for ongoing conflict
  if (await getConflictInfo()) {
    // Exit with instructions
  }

  // 3. Inject missing IDs
  await injectMissingIds();

  // 4. Parse stack
  const result = await parseStack();

  // 5. Rebase if behind
  if (await isStackBehindMain()) {
    const rebaseResult = await rebaseOntoMain();
    if (!rebaseResult.success) {
      // Conflict - exit
    }

    // Re-parse after rebase (hashes changed)
    result = await parseStack();
  }

  // 6. Update branches
  await syncAfterRebase(result.units);

  // 7. Create PRs if --open
  if (options.open) {
    await createMissingPRs(result.units);
  }
}
```

