// src/cli/commands/sync.ts

export const syncCommand = new Command('sync')
  .description('Sync stack state with GitHub')
  .option('--open', 'Create PRs for units without them')
  .action(async (options) => {
    await requireCleanWorkingTree();

    // Parse and validate stack
    const result = await parseStack();
    if (!result.ok) {
      console.error(formatValidationError(result));
      process.exit(1);
    }

    // Inject missing IDs
    const idResult = await injectMissingIds();
    if (idResult.modifiedCommits.length > 0) {
      console.log(\`✓ Added IDs to \${idResult.modifiedCommits.length} commit(s)\`);
      // Re-parse after rebase
      result = await parseStack();
    }

    if (!options.open) {
      console.log('✓ Stack synced (use --open to create PRs)');
      return;
    }

    // Push branches and create PRs
    const config = await getBranchNameConfig();
    const defaultBranch = await getDefaultBranch();

    let baseBranch = defaultBranch;
    const created: PRInfo[] = [];
    const existing: PRInfo[] = [];

    for (const unit of result.units) {
      const headBranch = getBranchName(unit.id, config);

      // Push branch
      await pushBranch(unit.commits[unit.commits.length - 1], headBranch);

      // Check for existing PR
      const existingPR = await findPRByBranch(headBranch);

      if (existingPR) {
        existing.push(existingPR);
      } else {
        const pr = await createPR({
          title: unit.title,
          head: headBranch,
          base: baseBranch,
        });
        created.push(pr);
      }

      baseBranch = headBranch;
    }

    // Report results
    if (created.length > 0) {
      console.log(\`\\n✓ Created \${created.length} PR(s):\`);
      for (const pr of created) {
        console.log(\`  #\${pr.number} \${pr.url}\`);
      }
    }

    if (existing.length > 0) {
      console.log(\`\\n✓ \${existing.length} PR(s) already exist\`);
    }
  });
```

