Update all rebase plumbing operations to preserve merge commit structure, including parent relationships and tree content.

## Context

Currently, rebase operations assume single-parent commits. When rebasing a merge commit, only the first parent is used and the merge structure is lost. We need to preserve all parent relationships and the merge resolution tree.

**Key insight:** The plumbing layer already supports merge commits - `getParents()` returns all parents and `createCommit()` accepts multiple parents. We just need to use them correctly.

## Changes Required

### 1. Update rewriteCommitChain (src/git/plumbing.ts:430-465)

Track and map all parents during message rewrites:

```typescript
export async function rewriteCommitChain(
  commits: string[],
  rewrites: Map<string, string>,
  options: GitOptions = {},
): Promise<ChainRewriteResult> {
  const mapping = new Map<string, string>();

  for (const originalHash of commits) {
    const tree = await getTree(originalHash, options);
    const env = await getAuthorAndCommitterEnv(originalHash, options);
    const originalParents = await getParents(originalHash, options);  // Use getParents (all)

    const newMessage = rewrites.get(originalHash) ?? 
      (await getCommitMessage(originalHash, options));

    // Map parents: if parent was rewritten, use new hash
    const newParents: string[] = [];
    for (const origParent of originalParents) {
      const mappedParent = mapping.get(origParent);
      if (mappedParent) {
        newParents.push(mappedParent);  // In our chain, rewritten
      } else {
        newParents.push(origParent);  // Outside chain, keep original
      }
    }

    // Create with all mapped parents
    const newHash = await createCommit(tree, newParents, newMessage, env, options);
    mapping.set(originalHash, newHash);
  }
  // ... return result
}
```

### 2. Update rebasePlumbing (src/git/plumbing.ts:507-549)

Detect and handle merge commits during cherry-pick:

```typescript
export async function rebasePlumbing(
  onto: string,
  commits: string[],
  options: GitOptions = {},
): Promise<PlumbingRebaseResult> {
  const mapping = new Map<string, string>();
  let currentTip = onto;

  for (const commit of commits) {
    const originalParents = await getParents(commit, options);
    const isMergeCommit = originalParents.length > 1;

    if (isMergeCommit) {
      // MERGE COMMIT: Map all parents and preserve tree
      const newParents: string[] = [];
      for (const originalParent of originalParents) {
        const newParent = mapping.get(originalParent);
        if (newParent) {
          newParents.push(newParent);  // Parent in rebase chain
        } else {
          newParents.push(originalParent);  // Parent outside chain
        }
      }

      // Preserve merge tree exactly (no re-merge)
      const tree = await getTree(commit, options);
      const message = await getCommitMessage(commit, options);
      const env = await getAuthorEnv(commit, options);

      const newHash = await createCommit(tree, newParents, message, env, options);
      mapping.set(commit, newHash);
      currentTip = newHash;

    } else {
      // REGULAR COMMIT: Three-way merge (existing logic)
      const originalParent = originalParents[0] || onto;
      const mergeResult = await mergeTree(originalParent, currentTip, commit, options);

      if (!mergeResult.ok) {
        return {
          ok: false,
          conflictCommit: commit,
          conflictInfo: mergeResult.conflictInfo,
        };
      }

      const message = await getCommitMessage(commit, options);
      const env = await getAuthorEnv(commit, options);
      const newHash = await createCommit(mergeResult.tree, [currentTip], message, env, options);

      mapping.set(commit, newHash);
      currentTip = newHash;
    }
  }

  return { ok: true, newTip: currentTip, mapping };
}
```

