### 4. Create merge validation module (src/git/merge-validation.ts - NEW)

```typescript
export interface MergeValidationResult {
  valid: boolean;
  errors: string[];
}

export async function validateMergeParents(
  options: GitOptions = {}
): Promise<MergeValidationResult> {
  const commits = await getStackCommitsWithTrailers(options);

  const idToHash = new Map<string, string>();
  for (const commit of commits) {
    const id = commit.trailers["Spry-Commit-Id"];
    if (id) idToHash.set(id, commit.hash);
  }

  const errors: string[] = [];

  for (const commit of commits) {
    const mergeParents = commit.trailers["Spry-Merge-Parents"];
    if (!Array.isArray(mergeParents) || mergeParents.length === 0) continue;

    // Check actual parent count matches
    if (commit.parents.length < 2) {
      errors.push(`Commit ${commit.hash.slice(0, 8)} has Spry-Merge-Parents but only ${commit.parents.length} parent(s)`);
    }

    // Check all merge parent IDs are reachable
    for (const parentId of mergeParents) {
      if (!idToHash.has(parentId)) {
        errors.push(`Commit ${commit.hash.slice(0, 8)} references unreachable merge parent: ${parentId}`);
      }
    }
  }

  return { valid: errors.length === 0, errors };
}
```

