Add command to recover flattened merge commits by reconstructing them from `Spry-Merge-Parents` trailers.

## Context

Users may perform rebases outside of spry (e.g., `git rebase`) that flatten merge commits into linear history. Since `Spry-Merge-Parents` trailers persist in commit messages, we can detect and recover these flattened merges.

## Use Case

```bash
# User has merge commits in spry
sp group  # Shows indented structure

# User does external rebase
git rebase -i origin/main  # Flattens merge commits

# Merge commits are now single-parent, but trailers remain
# Recovery command rebuilds them
sp group --recover
```

## Detection Logic

A flattened merge commit has:
1. `Spry-Merge-Parents` trailer (array with multiple values)
2. Only one actual parent (`parents.length === 1`)

This indicates the merge was flattened and needs recovery.

## Changes Required

### 1. Add --recover flag to group command (src/cli/commands/group.ts)

```typescript
export async function groupCommand(args: {
  recover?: boolean;
  // ... existing flags
}) {
  if (args.recover) {
    return await recoverCommand();
  }
  // ... existing group logic
}

async function recoverCommand() {
  const commits = await getStackCommitsWithTrailers();
  const flattenedMerges = detectFlattenedMerges(commits);

  if (flattenedMerges.length === 0) {
    console.log("No flattened merge commits detected.");
    return;
  }

  console.log(`Found ${flattenedMerges.length} flattened merge commit(s):`);
  for (const merge of flattenedMerges) {
    console.log(`  - ${merge.subject} (${merge.hash.slice(0, 8)})`);
  }

  // Confirm with user
  const confirmed = await confirm("Recover these merge commits?");
  if (!confirmed) return;

  // Perform recovery
  await recoverMergeCommits(flattenedMerges);

  console.log("✓ Merge commits recovered successfully.");
}
```

### 2. Create merge recovery module (src/git/merge-recovery.ts - NEW)

```typescript
export interface FlattenedMerge {
  hash: string;
  subject: string;
  body: string;
  trailers: CommitTrailers;
  mergeParentIds: string[];  // From Spry-Merge-Parents
  actualParents: string[];  // Current parent count
}

/**
 * Detect merge commits that have been flattened (single parent but has Spry-Merge-Parents).
 */
export function detectFlattenedMerges(
  commits: CommitWithTrailers[]
): FlattenedMerge[] {
  const flattened: FlattenedMerge[] = [];

  for (const commit of commits) {
    const mergeParents = commit.trailers["Spry-Merge-Parents"];

    // Check if has trailer but is not actually a merge
    if (Array.isArray(mergeParents) && mergeParents.length > 0) {
      if (commit.parents.length < 2) {
        flattened.push({
          hash: commit.hash,
          subject: commit.subject,
          body: commit.body,
          trailers: commit.trailers,
          mergeParentIds: mergeParents,
          actualParents: commit.parents,
        });
      }
    }
  }

  return flattened;
}

/**
 * Recover flattened merge commits by reconstructing them with multiple parents.
 */
export async function recoverMergeCommits(
  flattenedMerges: FlattenedMerge[],
  options: GitOptions = {}
): Promise<void> {
  await assertNotDetachedHead(options);

  const commits = await getStackCommitsWithTrailers(options);
  const idToHash = new Map<string, string>();

  for (const commit of commits) {
    const id = commit.trailers["Spry-Commit-Id"];
    if (id) idToHash.set(id, commit.hash);
  }

  // Build list of all commits to rewrite
  const allHashes = commits.map(c => c.hash);
  const rewrites = new Map<string, string>();  // hash -> new message (unchanged)
  const mergeReconstructions = new Map<string, string[]>();  // hash -> parent hashes

  for (const flattened of flattenedMerges) {
    // Resolve parent IDs to hashes
    const parentHashes: string[] = [];

    for (const parentId of flattened.mergeParentIds) {
      const parentHash = idToHash.get(parentId);
      if (!parentHash) {
        throw new Error(`Cannot recover merge ${flattened.hash.slice(0, 8)}: parent ID ${parentId} not found in stack`);
      }
      parentHashes.push(parentHash);
    }

    if (parentHashes.length < 2) {
      throw new Error(`Merge ${flattened.hash.slice(0, 8)} must have at least 2 parents`);
    }

    // Store parent hashes for reconstruction
    mergeReconstructions.set(flattened.hash, parentHashes);

    // Message stays the same (already has trailers)
    const originalMessage = await getCommitMessage(flattened.hash, options);
    rewrites.set(flattened.hash, originalMessage);
  }

  // Rewrite commit chain, reconstructing merges with multiple parents
  const branch = await getCurrentBranch(options);
  const oldTip = allHashes[allHashes.length - 1];

  const result = await rewriteCommitChainWithMerges(
    allHashes,
    rewrites,
    mergeReconstructions,
    options
  );

  await finalizeRewrite(branch, oldTip, result.newTip, options);
}

/**
 * Extended rewriteCommitChain that reconstructs merge commits.
 */
async function rewriteCommitChainWithMerges(
  commits: string[],
  rewrites: Map<string, string>,
  mergeReconstructions: Map<string, string[]>,
  options: GitOptions = {},
): Promise<ChainRewriteResult> {
  const mapping = new Map<string, string>();

  for (const originalHash of commits) {
    const tree = await getTree(originalHash, options);
    const env = await getAuthorAndCommitterEnv(originalHash, options);
    const message = rewrites.get(originalHash) ?? await getCommitMessage(originalHash, options);

    // Check if this is a merge to reconstruct
    const reconstructParents = mergeReconstructions.get(originalHash);

    let newParents: string[];
    if (reconstructParents) {
      // Reconstruct merge: map original parents to new hashes
      newParents = reconstructParents.map(p => mapping.get(p) ?? p);
    } else {
      // Regular commit: use existing parent mapping logic
      const originalParents = await getParents(originalHash, options);
      newParents = originalParents.map(p => mapping.get(p) ?? p);
    }

    const newHash = await createCommit(tree, newParents, message, env, options);
    mapping.set(originalHash, newHash);
  }

  const lastCommit = commits[commits.length - 1];
  const newTip = mapping.get(lastCommit)!;

  return { newTip, mapping };
}
```

