export function indentCommit(state: TUIState): TUIState {
  if (state.moveMode === null) return state;

  const currentIdx = state.moveMode;
  const currentLevel = state.indentLevels.get(currentIdx) ?? 0;

  // Validation: already indented or at top
  if (currentLevel === 1 || currentIdx === 0) return state;

  // Check if previous commit is also indented (contiguous block)
