  // Indentation (extra spaces for indented commits)
  if (indentLevel === 1) {
    parts.push("  ");  // Two spaces
  }

  // Merge commit indicator
  if (isMerge) {
    parts.push(` ${colors.blue("⎇")}`);  // Git merge symbol, dimmed
  } else if (group) {
    parts.push(` ${colors.magenta(group)}`);
  } else {
    parts.push(" ─");
  }

  // Hash and subject (dim for merge commits)
  if (isMerge) {
    parts.push(` ${colors.dim("(merge)")}`);
    parts.push(`  ${colors.dim(commit.subject)}`);
  } else {
